.darma-loader-flip-square {
  display: inline-block;
  width: 48px;
  height: 48px;
  border-radius: 14px;
  background: var(--loader-color, #6366f1);
  animation: darma-loader-flip-square-flip 1.15s cubic-bezier(.7,.02,.26,.99) infinite;
}
@keyframes darma-loader-flip-square-flip {
  0% { transform: perspective(120px) rotateX(0) rotateY(0); }
  50% { transform: perspective(120px) rotateX(-180deg) rotateY(0); }
  100% { transform: perspective(120px) rotateX(-180deg) rotateY(-180deg); }
}

